function solve(n: number, edges: number[][], k: number): number {
    // Sort edges by time to process them in order
    edges.sort((a, b) => a[2] - b[2]);

    // Build adjacency list
    const adj: Map<number, [number, number][]> = new Map();
    for (const [u, v, t] of edges) {
        if (!adj.has(u)) adj.set(u, []);
        if (!adj.has(v)) adj.set(v, []);
        adj.get(u)!.push([v, t]);
        adj.get(v)!.push([u, t]);
    }

    // Initialize the answer with the maximum possible time
    let answer: number = Number.MAX_VALUE;

    // Use a Union-Find (Disjoint Set Union) data structure to track connected components
    const parent: number[] = Array(n).fill(0).map((_, i) => i);
    const rank: number[] = Array(n).fill(1);

    function find(u: number): number {
        while (parent[u] !== u) {
            parent[u] = parent[parent[u]]; // Path compression
            u = parent[u];
        }
        return u;
    }

    function union(u: number, v: number): boolean {
        const u_root = find(u);
        const v_root = find(v);
        if (u_root === v_root) {
            return false;
        }
        if (rank[u_root] < rank[v_root]) {
            parent[u_root] = v_root;
            rank[v_root] += rank[u_root];
        } else {
            parent[v_root] = u_root;
            rank[u_root] += rank[v_root];
        }
        return true;
    }

    // Process edges in order of increasing time
    for (const [u, v, t] of edges) {
        // Union the nodes before removing the edge
        union(u, v);

        // Check if the number of connected components is at least k
        // Count the number of unique roots
        const roots: Set<number> = new Set();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        if (roots.size >= k) {
            answer = Math.min(answer, t);
        }
    }

